// DESIGN SPEC — generated by Designer agent
// Coder: implement TODO items, do not change component structure or accessibility attributes
//
// TopbarActionButton
// ──────────────────
// Pill-shaped button used in the right side of the workspace top toolbar.
// Three visual variants match the three right-side actions in the approved
// mockup:
//   • "default" — neutral pill (e.g. OpenImago community link)
//   • "pro"     — bright purple-gradient pill ("升级到 Pro")
//   • "bell"    — small icon-only button for notifications
//
// Slot-friendly: pass a `leading-icon` (or default slot content) plus a label.
// The button stays a real native button element for keyboard accessibility
// and uses aria-label when the label is suppressed.

<template>
  <button
    type="button"
    class="topbar-action"
    :class="[ 'topbar-action-' + variant, iconOnly ? 'topbar-action-icon-only' : '' ]"
    :aria-label="computedAriaLabel"
    :aria-haspopup="hasPopup ? 'menu' : undefined"
    @click="handleClick"
  >
    <span
      v-if="hasLeadingIconSlot || leadingIcon"
      class="topbar-action__icon"
      aria-hidden="true"
    >
      <slot name="leading-icon">
        <OiIcon
          v-if="leadingIcon"
          :name="leadingIcon as OiIconName"
          :size="iconSize"
        />
      </slot>
    </span>
    <span v-if="!iconOnly" class="topbar-action__label">
      <slot>{{ label }}</slot>
    </span>
    <span
      v-if="trailingIcon"
      class="topbar-action__trailing"
      aria-hidden="true"
    >
      <OiIcon
        :name="trailingIcon as OiIconName"
        :size="iconSize - 2"
      />
    </span>
    <span
      v-if="badge"
      class="topbar-action__badge"
      aria-hidden="true"
    ></span>
  </button>
</template>

<script setup lang="ts">
import { computed, useSlots } from 'vue'
import OiIcon from 'src/components/ui/OiIcon.vue'
import type { OiIconName } from 'src/components/ui/OiIcon.vue'

const props = withDefaults(defineProps<{
  variant?: 'default' | 'pro' | 'bell' | 'pro-glow'
  label?: string
  leadingIcon?: string | null
  trailingIcon?: string | null
  iconSize?: number
  iconOnly?: boolean
  hasPopup?: boolean
  /** Optional small dot badge — used by the bell for unread state. */
  badge?: boolean
  /** Override the accessible label; falls back to label. */
  ariaLabel?: string
}>(), {
  variant: 'default',
  label: '',
  leadingIcon: null,
  trailingIcon: null,
  iconSize: 16,
  iconOnly: false,
  hasPopup: false,
  badge: false,
  ariaLabel: '',
})

const emit = defineEmits<{
  (e: 'click', payload: MouseEvent): void
}>()

const slots = useSlots()
const hasLeadingIconSlot = computed(() => Boolean(slots['leading-icon']))

const computedAriaLabel = computed(() => {
  if (props.ariaLabel) return props.ariaLabel
  if (props.iconOnly) return props.label || '操作'
  return props.label
})

function handleClick(event: MouseEvent): void {
  emit('click', event)
}
</script>

